import numpy as np

def solve(grid):
    grid = [list(row) for row in grid]
    H, W = len(grid), len(grid[0])
    bg = 7

    # Find connected components (8-connected)
    visited = [[False]*W for _ in range(H)]
    components = []

    for r in range(H):
        for c in range(W):
            if grid[r][c] != bg and not visited[r][c]:
                comp = []
                q = [(r, c)]
                visited[r][c] = True
                while q:
                    cr, cc = q.pop()
                    comp.append((cr, cc))
                    for dr in [-1, 0, 1]:
                        for dc in [-1, 0, 1]:
                            if dr == 0 and dc == 0: continue
                            nr, nc = cr+dr, cc+dc
                            if 0 <= nr < H and 0 <= nc < W and not visited[nr][nc] and grid[nr][nc] != bg:
                                visited[nr][nc] = True
                                q.append((nr, nc))
                components.append(comp)

    # For each component, find junction and compute mark
    comp_info = []
    for comp in components:
        # Junction = cell with min sum of squared distances
        best_cell = None
        best_score = float('inf')
        for r1, c1 in comp:
            score = sum((r1-r2)**2 + (c1-c2)**2 for r2, c2 in comp if (r2,c2) != (r1,c1))
            if score < best_score:
                best_score = score
                best_cell = (r1, c1)

        junction = best_cell
        non_junc = [(r,c) for r,c in comp if (r,c) != junction]
        avg_r = sum(r for r,c in non_junc) / len(non_junc)
        avg_c = sum(c for r,c in non_junc) / len(non_junc)

        dr = junction[0] - avg_r
        dc = junction[1] - avg_c
        dir_r = 1 if dr > 0.01 else (-1 if dr < -0.01 else 0)
        dir_c = 1 if dc > 0.01 else (-1 if dc < -0.01 else 0)

        mark = (junction[0] + 5*dir_r, junction[1] + 5*dir_c)

        comp_info.append({
            'cells': set(comp),
            'junction': junction,
            'direction': (dir_r, dir_c),
            'mark': mark
        })

    # Build set of all component cells
    all_comp_cells = {}
    for i, info in enumerate(comp_info):
        for cell in info['cells']:
            all_comp_cells[cell] = i

    # Place marks and handle overlaps
    output = [row[:] for row in grid]
    mark_counts = {}
    mark_to_comps = {}

    for i, info in enumerate(comp_info):
        mr, mc = info['mark']
        if 0 <= mr < H and 0 <= mc < W:
            if (mr, mc) not in mark_counts:
                mark_counts[(mr, mc)] = 0
                mark_to_comps[(mr, mc)] = []
            mark_counts[(mr, mc)] += 1
            mark_to_comps[(mr, mc)].append(i)

    # Place marks
    for (mr, mc), count in mark_counts.items():
        if count > 1:
            output[mr][mc] = 1  # overlap → blue
        else:
            output[mr][mc] = 9

        # Check if mark lands on an existing component cell
        if (mr, mc) in all_comp_cells:
            comp_idx = all_comp_cells[(mr, mc)]
            # Recolor entire component to 9
            for r, c in comp_info[comp_idx]['cells']:
                output[r][c] = 9

    return output

# Test on training examples
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        result_arr = np.array(result)
        expected_arr = np.array(expected)
        diffs = np.argwhere(result_arr != expected_arr)
        for r, c in diffs:
            print(f"  ({int(r)},{int(c)}): expected {int(expected_arr[r,c])}, got {int(result_arr[r,c])}")

